<script setup lang="ts">
import { onMounted } from 'vue'; import { useRoute } from 'vue-router'; import StatusTag from '../components/common/StatusTag.vue'; import StudentAvatar from '../components/common/StudentAvatar.vue'; import ScoreDisplay from '../components/common/ScoreDisplay.vue'; import { useCourseStore } from '../stores/courseStore'; import { useStudentStore } from '../stores/studentStore'; import { useAssignmentStore } from '../stores/assignmentStore'; import { useAttendanceStore } from '../stores/attendanceStore';
const route = useRoute(); const courses = useCourseStore(); const students = useStudentStore(); const assignments = useAssignmentStore(); const attendance = useAttendanceStore();
onMounted(async()=>{ const id=route.params.id as string; await Promise.all([courses.fetchOne(id), students.fetch(), assignments.fetch(id), attendance.fetch({course_id:id})]); });
</script><template><section class="page" v-if="courses.current"><header><div><h2>{{ courses.current.name }}</h2><p>{{ courses.current.code }} · {{ courses.current.teacher_name }} · {{ courses.current.semester }}</p></div><StatusTag :status="courses.current.status" type="course" /></header><el-tabs><el-tab-pane label="学生名单"><el-table :data="students.items"><el-table-column label="学生"><template #default="{row}"><StudentAvatar :student="row"/></template></el-table-column><el-table-column prop="grade" label="年级"/><el-table-column prop="email" label="邮箱"/></el-table></el-tab-pane><el-tab-pane label="作业列表"><el-table :data="assignments.items"><el-table-column prop="title" label="标题"/><el-table-column prop="type" label="类型"/><el-table-column label="状态"><template #default="{row}"><StatusTag :status="row.status" type="assignment"/></template></el-table-column><el-table-column prop="submissions_count" label="提交"/></el-table></el-tab-pane><el-tab-pane label="考勤记录"><el-table :data="attendance.items"><el-table-column prop="student_name" label="学生"/><el-table-column prop="date" label="日期"/><el-table-column label="状态"><template #default="{row}"><StatusTag :status="row.status" type="attendance"/></template></el-table-column></el-table></el-tab-pane><el-tab-pane label="成绩汇总"><el-table :data="students.items"><el-table-column label="学生"><template #default="{row}"><StudentAvatar :student="row"/></template></el-table-column><el-table-column label="综合分"><template #default><ScoreDisplay :score="86" :total-score="100" show-bar /></template></el-table-column></el-table></el-tab-pane></el-tabs></section></template>